// frontend/src/components/BookingForm/BookingForm.jsx
import React, { useState, useEffect } from 'react';
import DatePicker from 'react-datepicker';
import 'react-datepicker/dist/react-datepicker.css';
import { createBooking, getAvailableDates } from '../../services/ApiService';
import './BookingForm.css';

export default function BookingForm({ onBookingSuccess }) {
  const [email, setEmail] = useState('');
  const [selectedDate, setSelectedDate] = useState(null);
  const [message, setMessage] = useState('');
  const [bookedDates, setBookedDates] = useState([]);
  const [availableDates, setAvailableDates] = useState([]);

  // Загружаем свободные даты для марта и все занятые даты с backend
  useEffect(() => {
    const fetchDates = async () => {
      try {
        // Только три дня в неделю марта (по заданию)
        const freeDates = await getAvailableDates(); 
        setAvailableDates(freeDates);

        // Берем все забронированные даты с backend
        const res = await fetch('http://localhost:5000/bookings');
        const data = await res.json();
        const booked = data.map(b => b.date);
        setBookedDates(booked);
      } catch (err) {
        console.error(err);
      }
    };
    fetchDates();
  }, []);

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!selectedDate) return;

    const dateStr = selectedDate.toISOString().split('T')[0];

    if (bookedDates.includes(dateStr)) {
      setMessage('Эта дата уже занята');
      return;
    }

    try {
      const res = await createBooking(dateStr, email);
      if (res.error) setMessage(res.error);
      else {
        setMessage('Вы успешно забронировались!');
        setBookedDates(prev => [...prev, dateStr]);
        setSelectedDate(null);
        setEmail('');
        if (onBookingSuccess) onBookingSuccess(); // обновление таблицы хозяина
      }
    } catch (err) {
      console.error(err);
      setMessage('Ошибка при создании брони');
    }
  };

  // Подсветка дней
  const highlightWithRanges = (date) => {
    const dateStr = date.toISOString().split('T')[0];
    if (bookedDates.includes(dateStr)) return 'booked-date';      // красный
    if (availableDates.includes(dateStr)) return 'available-date'; // черный
    return null;
  };

  const filterAvailableDates = (date) => date >= new Date(); // только будущие даты

  const navButtonStyle = {
    background: 'none',
    border: 'none',
    color: '#007BFF',
    fontSize: '16px',
    cursor: 'pointer',
    margin: '0 5px'
  };

  return (
    <form className="booking-form" onSubmit={handleSubmit}>
      <h2>Забронировать комнату</h2>

      <input
        type="email"
        placeholder="Ваш Email"
        value={email}
        onChange={(e) => setEmail(e.target.value)}
        required
      />

      <DatePicker
        selected={selectedDate}
        onChange={(date) => setSelectedDate(date)}
        dayClassName={(date) => highlightWithRanges(date)}
        filterDate={(date) => filterAvailableDates(date)}
        placeholderText="Выберите дату"
        dateFormat="yyyy-MM-dd"
        minDate={new Date()}
        showDisabledMonthNavigation
        showPopperArrow={false}
        todayButton={null}
        renderCustomHeader={({
          date,
          decreaseMonth,
          increaseMonth,
          prevMonthButtonDisabled,
          nextMonthButtonDisabled
        }) => (
          <div style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', marginBottom: '10px' }}>
            <button onClick={decreaseMonth} disabled={prevMonthButtonDisabled} style={navButtonStyle}>
              &lt;
            </button>
            <span style={{ margin: '0 10px', fontWeight: 'bold', fontSize: '16px' }}>
              {date.toLocaleString('ru-RU', { month: 'long', year: 'numeric' })}
            </span>
            <button onClick={increaseMonth} disabled={nextMonthButtonDisabled} style={navButtonStyle}>
              &gt;
            </button>
          </div>
        )}
      />

      <button type="submit">Забронировать</button>

      <p className={message.includes('занята') ? 'text-warning' : 'text-success'}>
        {message}
      </p>
    </form>
  );
}
